import { defineConfig, devices } from '@playwright/test';

/**
 * Shared authentication state file
 * This file is generated by tests/auth.setup.ts and contains the logged-in session
 */
const authFile = '.auth/user.json';

export default defineConfig({
  testDir: './tests',
  fullyParallel: true,
  forbidOnly: !!process.env.CI,
  retries: process.env.CI ? 2 : 0,
  workers: process.env.CI ? 1 : undefined,
  reporter: 'html',
  use: {
    baseURL: process.env.BASE_URL || 'http://localhost:9002',
    trace: 'on-first-retry',
    screenshot: 'only-on-failure',
  },

  projects: [
    // Global setup - runs FIRST to clean up any leftover test data
    {
      name: 'global-setup',
      testMatch: /global\.setup\.ts/,
    },

    // Auth setup - runs AFTER global cleanup to authenticate
    {
      name: 'auth-setup',
      testMatch: /auth\.setup\.ts/,
      dependencies: ['global-setup'],
    },

    // Consolidated data setup - runs ONCE after auth to seed ALL test data
    {
      name: 'data-setup',
      testMatch: /^.*\/tests\/data\.setup\.ts$/,
      dependencies: ['auth-setup'],
    },

    // Test projects - all use the shared authenticated state
    {
      name: 'chromium',
      use: {
        ...devices['Desktop Chrome'],
        // Use the saved authentication state
        storageState: authFile,
      },
      dependencies: ['data-setup'],
      testIgnore: /.*\.setup\.ts/,
    },
    // {
    //   name: 'firefox',
    //   use: {
    //     ...devices['Desktop Firefox'],
    //     storageState: authFile,
    //   },
    //   dependencies: ['setup'],
    // },
    // {
    //   name: 'webkit',
    //   use: {
    //     ...devices['Desktop Safari'],
    //     storageState: authFile,
    //   },
    //   dependencies: ['setup'],
    // },
  ],

  webServer: {
    command: 'cd ../../.. && ./gradlew quickstartDebug',
    url: 'http://localhost:9002',
    reuseExistingServer: !process.env.CI,
    timeout: 120 * 1000,
  },
});
